scripts.script:
// A continuous-axis heatmap: rows stay categorical (one sensor per row) while
// the x axis is a real datetime scale. Each cell sits at its true timestamp and
// the axis shows sparse proportional date/time ticks instead of one label per
// cell. Because cells are placed by value, an irregular gap in the data (here a
// simulated outage) shows up as real empty space, which index-based tiling
// cannot represent.
var HOUR = 60 * 60 * 1000
var start = new Date('2024-03-04T00:00:00.000Z').getTime()
var totalHours = 72

// A deterministic pseudo-random generator so the demo is stable across reloads.
function makeRand(seed) {
  var s = seed
  return function () {
    s = (s * 1103515245 + 12345) & 0x7fffffff
    return s / 0x7fffffff
  }
}

// Hours 30..41 are dropped for every sensor to simulate a 12-hour outage.
function isOutage(h) {
  return h >= 30 && h < 42
}

function sensorSeries(name, seed, base) {
  var rand = makeRand(seed)
  var data = []
  for (var h = 0; h < totalHours; h++) {
    if (isOutage(h)) continue
    // A daily rhythm plus noise, so the heat has visible structure.
    var hourOfDay = h % 24
    var daily = Math.sin((hourOfDay / 24) * Math.PI * 2) * 30 + 40
    var y = Math.max(0, Math.round(base + daily + (rand() - 0.5) * 20))
    data.push({ x: start + h * HOUR, y: y })
  }
  return { name: name, data: data }
}

var heatData = [
  sensorSeries('Sensor A', 7, 10),
  sensorSeries('Sensor B', 19, 20),
  sensorSeries('Sensor C', 42, 5),
  sensorSeries('Sensor D', 88, 25),
  sensorSeries('Sensor E', 123, 15),
  sensorSeries('Sensor F', 256, 0),
]

chart.options:
chart: {
  height: 320,
  type: 'heatmap',
  toolbar: { show: false },
},
dataLabels: {
  enabled: false,
},
colors: ['#008FFB'],
title: {
  text: 'Sensor readings over time (12-hour outage visible as a gap)',
  align: 'left',
},
xaxis: {
  type: 'datetime',
  labels: {
    datetimeUTC: true,
    datetimeFormatter: {
      year: 'yyyy',
      month: "MMM 'yy",
      day: 'MMM dd',
      hour: 'HH:mm',
    },
  },
},
tooltip: {
  x: { show: true, format: 'MMM dd HH:mm' },
},
